// GOVERNMENT
const jambGovernmentQuestions = [
  { id: 'gov21', year: 2024, topic: 'Political Systems', difficulty: 'easy', question: 'Which of the following is a feature of a unitary system of government?', options: ['A: Shared sovereignty', 'B: Single central authority', 'C: Written constitution only', 'D: Bicameral legislature'], answer: 'B', explanation: 'A unitary system vests all governmental powers in a single central authority.' },
  { id: 'gov22', year: 2024, topic: 'Political Systems', difficulty: 'medium', question: 'A major disadvantage of a federal system of government is the', options: ['A: concentration of power at the centre', 'B: high cost of administration', 'C: lack of local autonomy', 'D: absence of judicial review'], answer: 'B', explanation: 'Federalism requires multiple levels of government, making administration expensive.' },
  { id: 'gov23', year: 2024, topic: 'Political Systems', difficulty: 'medium', question: 'In a parliamentary system, the Head of Government is the', options: ['A: President', 'B: Prime Minister', 'C: Speaker', 'D: Chief Justice'], answer: 'B', explanation: 'The Prime Minister is the Head of Government in a parliamentary system.' },
  { id: 'gov24', year: 2024, topic: 'Political Systems', difficulty: 'easy', question: 'Which system of government is characterised by the fusion of powers?', options: ['A: Presidential', 'B: Parliamentary', 'C: Federal', 'D: Unitary'], answer: 'B', explanation: 'The parliamentary system fuses executive and legislative powers.' },
  { id: 'gov25', year: 2024, topic: 'Political Systems', difficulty: 'hard', question: 'One major advantage of a presidential system over a parliamentary system is the', options: ['A: stability of the executive', 'B: strict party discipline', 'C: collective responsibility', 'D: ease of removing the executive'], answer: 'A', explanation: 'The president serves a fixed term, providing executive stability.' },
  { id: 'gov26', year: 2024, topic: 'Constitution', difficulty: 'easy', question: 'A constitution is said to be rigid if it', options: ['A: can be amended by a simple majority', 'B: cannot be amended', 'C: requires a special procedure for amendment', 'D: is written by the judiciary'], answer: 'C', explanation: 'A rigid constitution requires a special, often more difficult, amendment process.' },
  { id: 'gov27', year: 2024, topic: 'Constitution', difficulty: 'medium', question: 'The 1999 Nigerian Constitution is primarily', options: ['A: monarchical', 'B: republican', 'C: aristocratic', 'D: dictatorial'], answer: 'B', explanation: 'The 1999 Constitution establishes Nigeria as a federal republic.' },
  { id: 'gov28', year: 2024, topic: 'Constitution', difficulty: 'medium', question: 'The supremacy of the constitution means that', options: ['A: parliament can override it', 'B: all laws must conform to it', 'C: the executive can suspend it', 'D: the judiciary is above it'], answer: 'B', explanation: 'Constitutional supremacy means every other law derives validity from and must conform to the constitution.' },
  { id: 'gov29', year: 2024, topic: 'Constitution', difficulty: 'hard', question: 'Which of the following is a feature of a federal constitution?', options: ['A: Centralisation of powers', 'B: Division of powers between central and regional governments', 'C: Absence of judicial interpretation', 'D: Unicameral legislature'], answer: 'B', explanation: 'A federal constitution divides powers between national and sub-national governments.' },
  { id: 'gov30', year: 2024, topic: 'Constitution', difficulty: 'easy', question: 'An unwritten constitution is associated with', options: ['A: the United States', 'B: Nigeria', 'C: the United Kingdom', 'D: France'], answer: 'C', explanation: 'The UK operates largely on conventions, statutes, and common law, forming an unwritten constitution.' },
  { id: 'gov31', year: 2024, topic: 'Executive & Legislature', difficulty: 'medium', question: 'The function of the executive includes', options: ['A: law-making', 'B: policy implementation', 'C: judicial review', 'D: interpretation of laws'], answer: 'B', explanation: 'The executive implements and enforces laws and policies.' },
  { id: 'gov32', year: 2024, topic: 'Executive & Legislature', difficulty: 'easy', question: 'A bill passed by the legislature but not yet signed into law is known as a', options: ['A: decree', 'B: act', 'C: bill', 'D: resolution'], answer: 'C', explanation: 'A bill becomes an act only after presidential assent.' },
  { id: 'gov33', year: 2024, topic: 'Executive & Legislature', difficulty: 'medium', question: 'Which of the following is a function of the legislature?', options: ['A: Adjudicating disputes', 'B: Making laws', 'C: Executing policies', 'D: Appointing judges'], answer: 'B', explanation: 'The primary function of the legislature is law-making.' },
  { id: 'gov34', year: 2024, topic: 'Executive & Legislature', difficulty: 'hard', question: 'The principle of collective responsibility applies in a', options: ['A: presidential system', 'B: parliamentary system', 'C: federal system', 'D: unitary system'], answer: 'B', explanation: 'In a parliamentary system, cabinet members are collectively responsible to parliament.' },
  { id: 'gov35', year: 2024, topic: 'Executive & Legislature', difficulty: 'easy', question: 'The head of the legislature in Nigeria is the', options: ['A: President', 'B: Chief Justice', 'C: Senate President', 'D: Speaker of the House'], answer: 'C', explanation: 'The Senate President is the presiding officer of the Nigerian Senate.' },
  { id: 'gov36', year: 2024, topic: 'Executive & Legislature', difficulty: 'medium', question: 'The process of law-making begins with the', options: ['A: first reading', 'B: second reading', 'C: third reading', 'D: committee stage'], answer: 'A', explanation: 'The first reading introduces the bill to the legislature without debate.' },
  { id: 'gov37', year: 2024, topic: 'Political Parties', difficulty: 'easy', question: 'A political party is primarily formed to', options: ['A: register voters', 'B: contest elections and govern', 'C: adjudicate disputes', 'D: conduct censuses'], answer: 'B', explanation: 'Political parties aim to gain power through elections and form government.' },
  { id: 'gov38', year: 2024, topic: 'Political Parties', difficulty: 'medium', question: 'Which of the following is a feature of a two-party system?', options: ['A: Many parties share power', 'B: Only two parties have a realistic chance of winning', 'C: Only two parties are legally allowed', 'D: One party dominates permanently'], answer: 'B', explanation: 'A two-party system means two major parties compete for power, though minor parties may exist.' },
  { id: 'gov39', year: 2024, topic: 'Political Parties', difficulty: 'medium', question: 'The main function of an opposition party is to', options: ['A: support the government unconditionally', 'B: provide alternative policies and criticize the government', 'C: merge with the ruling party', 'D: conduct elections'], answer: 'B', explanation: 'The opposition checks government excesses and offers alternative policies.' },
  { id: 'gov40', year: 2024, topic: 'Political Parties', difficulty: 'hard', question: 'A party system in which only one party is permitted to operate is called', options: ['A: dominant party system', 'B: one-party system', 'C: two-party system', 'D: multi-party system'], answer: 'B', explanation: 'A one-party system legally restricts political participation to a single party.' },
  { id: 'gov41', year: 2024, topic: 'Political Parties', difficulty: 'easy', question: 'The party that wins the majority of seats in a parliamentary election forms the', options: ['A: opposition', 'B: government', 'C: judiciary', 'D: electoral commission'], answer: 'B', explanation: 'The majority party forms the government in a parliamentary system.' },
  { id: 'gov42', year: 2024, topic: 'International Organizations', difficulty: 'easy', question: 'The United Nations was founded in the year', options: ['A: 1919', 'B: 1945', 'C: 1960', 'D: 1948'], answer: 'B', explanation: 'The UN was established in 1945 after World War II.' },
  { id: 'gov43', year: 2024, topic: 'International Organizations', difficulty: 'medium', question: 'The principal judicial organ of the United Nations is the', options: ['A: Security Council', 'B: General Assembly', 'C: International Court of Justice', 'D: Secretariat'], answer: 'C', explanation: 'The ICJ settles legal disputes between states.' },
  { id: 'gov44', year: 2024, topic: 'International Organizations', difficulty: 'medium', question: 'Which organ of the UN is primarily responsible for maintaining international peace and security?', options: ['A: Trusteeship Council', 'B: Economic and Social Council', 'C: Security Council', 'D: General Assembly'], answer: 'C', explanation: 'The Security Council has primary responsibility for peace and security.' },
  { id: 'gov45', year: 2024, topic: 'International Organizations', difficulty: 'hard', question: 'The African Union (AU) was established to replace the', options: ['A: ECOWAS', 'B: OAU', 'C: UN', 'D: Commonwealth'], answer: 'B', explanation: 'The AU succeeded the Organisation of African Unity (OAU) in 2002.' },
  { id: 'gov46', year: 2024, topic: 'International Organizations', difficulty: 'easy', question: 'Nigeria is a member of all the following international organisations EXCEPT', options: ['A: United Nations', 'B: African Union', 'C: European Union', 'D: ECOWAS'], answer: 'C', explanation: 'The EU is a European regional organisation; Nigeria is not a member.' },
  { id: 'gov47', year: 2024, topic: 'International Organizations', difficulty: 'medium', question: 'The headquarters of the International Monetary Fund (IMF) is located in', options: ['A: New York', 'B: London', 'C: Washington D.C.', 'D: Geneva'], answer: 'C', explanation: 'The IMF is headquartered in Washington D.C., USA.' },
  { id: 'gov48', year: 2024, topic: 'Citizenship', difficulty: 'easy', question: 'Citizenship refers to the', options: ['A: right to vote only', 'B: legal membership of a state', 'C: place of birth', 'D: ethnic identity of a person'], answer: 'B', explanation: 'Citizenship is the legal bond between an individual and a state.' },
  { id: 'gov49', year: 2024, topic: 'Citizenship', difficulty: 'medium', question: 'Citizenship by naturalisation is acquired through', options: ['A: birth within the country', 'B: marriage to a citizen', 'C: a formal legal process', 'D: descent from citizen parents'], answer: 'C', explanation: 'Naturalisation is a legal process by which a foreigner becomes a citizen.' },
  { id: 'gov50', year: 2024, topic: 'Citizenship', difficulty: 'medium', question: 'A person who is not a citizen of a country but resides there is called an', options: ['A: indigene', 'B: alien', 'C: refugee', 'D: emigrant'], answer: 'B', explanation: 'An alien is a foreigner residing in a country of which they are not a citizen.' },
  { id: 'gov51', year: 2024, topic: 'Citizenship', difficulty: 'hard', question: 'Citizenship can be lost through all the following EXCEPT', options: ['A: renunciation', 'B: deprivation', 'C: registration', 'D: dual citizenship'], answer: 'C', explanation: 'Registration is a method of acquiring citizenship, not losing it.' },
  { id: 'gov52', year: 2024, topic: 'Citizenship', difficulty: 'easy', question: 'The principle that a child acquires the citizenship of the country of birth is called', options: ['A: jus sanguinis', 'B: jus soli', 'C: naturalisation', 'D: dual citizenship'], answer: 'B', explanation: 'Jus soli means right of soil, i.e., citizenship by place of birth.' },
  { id: 'gov53', year: 2024, topic: 'Colonial Administration', difficulty: 'medium', question: 'Indirect rule in Nigeria was practised mainly by the', options: ['A: French', 'B: Portuguese', 'C: British', 'D: Germans'], answer: 'C', explanation: 'The British adopted indirect rule, governing through traditional rulers.' },
  { id: 'gov54', year: 2024, topic: 'Colonial Administration', difficulty: 'medium', question: 'The policy of assimilation was practised by the', options: ['A: British', 'B: French', 'C: Dutch', 'D: Spanish'], answer: 'B', explanation: 'France used assimilation, aiming to make colonial subjects French citizens.' },
  { id: 'gov55', year: 2024, topic: 'Colonial Administration', difficulty: 'hard', question: 'One major criticism of indirect rule in Nigeria was that it', options: ['A: empowered traditional rulers excessively', 'B: promoted western education', 'C: encouraged nationalism', 'D: created a centralised government'], answer: 'A', explanation: 'Indirect rule gave traditional rulers too much power, often making them autocratic.' },
  { id: 'gov56', year: 2024, topic: 'Colonial Administration', difficulty: 'easy', question: 'The Berlin Conference of 1884-1885 was primarily about', options: ['A: the abolition of slave trade', 'B: the partition of Africa', 'C: the formation of the UN', 'D: the independence of colonies'], answer: 'B', explanation: 'The Berlin Conference regulated European colonisation and partition of Africa.' },
  { id: 'gov57', year: 2024, topic: 'Colonial Administration', difficulty: 'medium', question: 'Which colonial power used the policy of association in West Africa?', options: ['A: Britain', 'B: France', 'C: Germany', 'D: Italy'], answer: 'B', explanation: 'France later replaced assimilation with association, which allowed some local traditions.' },
  { id: 'gov58', year: 2024, topic: 'Colonial Administration', difficulty: 'hard', question: 'The system of colonial administration that allowed settlers to govern themselves while the colony administered its internal affairs is called', options: ['A: indirect rule', 'B: direct rule', 'C: responsible government', 'D: crown colony system'], answer: 'C', explanation: 'Responsible government gave colonies control over internal affairs while foreign policy remained with the imperial power.' },
  { id: 'gov59', year: 2024, topic: 'Local Government', difficulty: 'easy', question: 'The tier of government closest to the people is the', options: ['A: federal government', 'B: state government', 'C: local government', 'D: municipal council'], answer: 'C', explanation: 'Local government is the grassroots level of governance.' },
  { id: 'gov60', year: 2024, topic: 'Local Government', difficulty: 'medium', question: 'The main source of revenue for local governments in Nigeria is the', options: ['A: value added tax', 'B: personal income tax', 'C: federal allocation', 'D: customs duties'], answer: 'C', explanation: 'Local governments rely heavily on monthly allocations from the Federation Account.' },
  { id: 'gov61', year: 2024, topic: 'Local Government', difficulty: 'medium', question: 'A major function of local government is the', options: ['A: maintenance of armed forces', 'B: provision of primary education', 'C: printing of currency', 'D: conduct of foreign policy'], answer: 'B', explanation: 'Local government is responsible for primary education and basic services.' },
  { id: 'gov62', year: 2024, topic: 'Local Government', difficulty: 'hard', question: 'The chairman of a local government in Nigeria serves a term of', options: ['A: 2 years', 'B: 3 years', 'C: 4 years', 'D: 5 years'], answer: 'B', explanation: 'Local government chairmen in Nigeria serve a three-year term.' },
  { id: 'gov63', year: 2024, topic: 'Local Government', difficulty: 'easy', question: 'Local government is also known as', options: ['A: central government', 'B: regional government', 'C: grassroots government', 'D: federal government'], answer: 'C', explanation: 'Local government is often called grassroots government because of its proximity to the people.' },
  { id: 'gov64', year: 2024, topic: 'Public Administration', difficulty: 'medium', question: 'The process of recruitment into the civil service is based on', options: ['A: patronage', 'B: merit and qualification', 'C: political affiliation', 'D: ethnic background'], answer: 'B', explanation: 'Civil service recruitment is supposed to be merit-based.' },
  { id: 'gov65', year: 2024, topic: 'Public Administration', difficulty: 'medium', question: 'The head of the Nigerian civil service is the', options: ['A: President', 'B: Head of Service', 'C: Chief of Staff', 'D: Secretary to the Government'], answer: 'B', explanation: 'The Head of Service is the administrative head of the civil service.' },
  { id: 'gov66', year: 2024, topic: 'Public Administration', difficulty: 'hard', question: 'The principle that civil servants should remain politically neutral is called', options: ['A: anonymity', 'B: impartiality', 'C: permanence', 'D: neutrality'], answer: 'B', explanation: 'Impartiality requires civil servants to serve any government regardless of party.' },
  { id: 'gov67', year: 2024, topic: 'Public Administration', difficulty: 'easy', question: 'Which of the following is a characteristic of the civil service?', options: ['A: Partisanship', 'B: Anonymity', 'C: Political appointment', 'D: Temporary tenure'], answer: 'B', explanation: 'Civil servants serve anonymously, with ministers taking credit or blame.' },
  { id: 'gov68', year: 2024, topic: 'Public Administration', difficulty: 'medium', question: 'The minister responsible for a ministry is a', options: ['A: civil servant', 'B: political appointee', 'C: permanent secretary', 'D: public servant'], answer: 'B', explanation: 'Ministers are political appointees, not career civil servants.' },
  { id: 'gov69', year: 2024, topic: 'Pressure Groups', difficulty: 'easy', question: 'A pressure group is primarily concerned with', options: ['A: contesting elections', 'B: influencing government policies', 'C: forming a government', 'D: adjudicating disputes'], answer: 'B', explanation: 'Pressure groups seek to influence policy without directly seeking power.' },
  { id: 'gov70', year: 2024, topic: 'Pressure Groups', difficulty: 'medium', question: 'The Nigeria Labour Congress (NLC) is an example of a', options: ['A: political party', 'B: pressure group', 'C: government agency', 'D: judicial body'], answer: 'B', explanation: 'The NLC is a trade union pressure group advocating for workers rights.' },
  { id: 'gov71', year: 2024, topic: 'Pressure Groups', difficulty: 'medium', question: 'Pressure groups differ from political parties because they', options: ['A: seek to win elections', 'B: do not nominate candidates', 'C: have wider membership', 'D: are always legal'], answer: 'B', explanation: 'Unlike political parties, pressure groups do not field candidates for elections.' },
  { id: 'gov72', year: 2024, topic: 'Pressure Groups', difficulty: 'hard', question: 'Which of the following methods is commonly used by pressure groups?', options: ['A: Nominating candidates', 'B: Lobbying', 'C: Forming a government', 'D: Passing laws'], answer: 'B', explanation: 'Lobbying is a key method pressure groups use to influence decision-makers.' },
  { id: 'gov73', year: 2024, topic: 'Pressure Groups', difficulty: 'easy', question: 'An interest group that seeks to promote the welfare of its members is called a', options: ['A: promotional group', 'B: institutional group', 'C: sectional group', 'D: political group'], answer: 'C', explanation: 'Sectional groups protect the interests of their specific members.' },
  { id: 'gov74', year: 2024, topic: 'Judiciary', difficulty: 'medium', question: 'The power of the judiciary to declare laws unconstitutional is known as', options: ['A: judicial review', 'B: judicial precedence', 'C: habeas corpus', 'D: judicial immunity'], answer: 'A', explanation: 'Judicial review allows courts to invalidate laws that violate the constitution.' },
  { id: 'gov75', year: 2024, topic: 'Judiciary', difficulty: 'medium', question: 'The highest court in Nigeria is the', options: ['A: Court of Appeal', 'B: Supreme Court', 'C: Federal High Court', 'D: Sharia Court of Appeal'], answer: 'B', explanation: 'The Supreme Court is the apex court in Nigeria.' },
  { id: 'gov76', year: 2024, topic: 'Judiciary', difficulty: 'hard', question: 'The doctrine of separation of powers was popularised by', options: ['A: John Locke', 'B: Montesquieu', 'C: Jean Bodin', 'D: Thomas Hobbes'], answer: 'B', explanation: 'Montesquieu articulated the separation of powers into executive, legislature, and judiciary.' },
  { id: 'gov77', year: 2024, topic: 'Judiciary', difficulty: 'easy', question: 'The independence of the judiciary is essential for', options: ['A: executive supremacy', 'B: the rule of law', 'C: legislative dominance', 'D: party control'], answer: 'B', explanation: 'An independent judiciary upholds the rule of law and checks other branches.' },
  { id: 'gov78', year: 2024, topic: 'Judiciary', difficulty: 'medium', question: 'Judges in the Nigerian Supreme Court are appointed by the', options: ['A: President on the recommendation of the NJC', 'B: Chief Justice alone', 'C: Senate', 'D: Attorney General'], answer: 'A', explanation: 'The President appoints Supreme Court justices based on NJC recommendation.' },
  { id: 'gov79', year: 2024, topic: 'Human Rights', difficulty: 'easy', question: 'Fundamental human rights are contained in which chapter of the 1999 Nigerian Constitution?', options: ['A: Chapter I', 'B: Chapter II', 'C: Chapter IV', 'D: Chapter VII'], answer: 'C', explanation: 'Chapter IV of the 1999 Constitution covers fundamental human rights.' },
  { id: 'gov80', year: 2024, topic: 'Human Rights', difficulty: 'medium', question: 'The right to life is an example of a', options: ['A: social right', 'B: economic right', 'C: fundamental right', 'D: political right'], answer: 'C', explanation: 'The right to life is a fundamental human right protected by the constitution.' },
  { id: 'gov81', year: 2024, topic: 'Human Rights', difficulty: 'medium', question: 'The writ of habeas corpus is used to enforce the right to', options: ['A: vote', 'B: personal liberty', 'C: education', 'D: fair hearing'], answer: 'B', explanation: 'Habeas corpus protects against unlawful detention and enforces personal liberty.' },
  { id: 'gov82', year: 2024, topic: 'Human Rights', difficulty: 'hard', question: 'Which of the following rights is NOT included in the 1999 Nigerian Constitution?', options: ['A: Right to life', 'B: Right to education', 'C: Right to fair hearing', 'D: Freedom of expression'], answer: 'B', explanation: 'The right to education is in Chapter II (non-justiciable), not Chapter IV (justiciable rights).' },
  { id: 'gov83', year: 2024, topic: 'Human Rights', difficulty: 'easy', question: 'The Universal Declaration of Human Rights was adopted in', options: ['A: 1945', 'B: 1948', 'C: 1960', 'D: 1950'], answer: 'B', explanation: 'The UDHR was adopted by the UN General Assembly in 1948.' },
  { id: 'gov84', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'medium', question: 'The body responsible for conducting elections in Nigeria is the', options: ['A: INEC', 'B: NUC', 'C: NAFDAC', 'D: NCC'], answer: 'A', explanation: 'INEC, the Independent National Electoral Commission, conducts federal elections.' },
  { id: 'gov85', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'medium', question: 'An electoral system where the candidate with the highest votes wins, regardless of majority, is called', options: ['A: proportional representation', 'B: first-past-the-post', 'C: absolute majority', 'D: preferential voting'], answer: 'B', explanation: 'First-past-the-post awards victory to the candidate with the most votes.' },
  { id: 'gov86', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'hard', question: 'Proportional representation aims to', options: ['A: ensure the winner takes all', 'B: allocate seats based on vote share', 'C: eliminate minor parties', 'D: simplify the ballot'], answer: 'B', explanation: 'PR allocates legislative seats in proportion to votes received.' },
  { id: 'gov87', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'easy', question: 'A referendum is a form of', options: ['A: direct democracy', 'B: representative democracy', 'C: oligarchy', 'D: aristocracy'], answer: 'A', explanation: 'A referendum allows citizens to vote directly on a policy or constitutional issue.' },
  { id: 'gov88', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'medium', question: 'The minimum voting age in Nigeria is', options: ['A: 16 years', 'B: 17 years', 'C: 18 years', 'D: 21 years'], answer: 'C', explanation: 'Nigeria sets the voting age at 18 years.' },
  { id: 'gov89', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'hard', question: 'A by-election is held to', options: ['A: elect a new government', 'B: fill a vacant seat between general elections', 'C: vote on a constitutional amendment', 'D: recall an elected official'], answer: 'B', explanation: 'A by-election fills a legislative vacancy occurring during a term.' },
  { id: 'gov90', year: 2024, topic: 'Public Opinion', difficulty: 'easy', question: 'Public opinion refers to the', options: ['A: views of the government', 'B: collective views of citizens on public issues', 'C: opinions of the media only', 'D: decisions of the judiciary'], answer: 'B', explanation: 'Public opinion is the aggregate of individual attitudes on matters of public concern.' },
  { id: 'gov91', year: 2024, topic: 'Public Opinion', difficulty: 'medium', question: 'Which of the following is an agent of public opinion formation?', options: ['A: The police', 'B: The mass media', 'C: The armed forces', 'D: The civil service'], answer: 'B', explanation: 'The mass media shapes and influences public opinion significantly.' },
  { id: 'gov92', year: 2024, topic: 'Public Opinion', difficulty: 'medium', question: 'Public opinion can be measured through', options: ['A: elections', 'B: opinion polls', 'C: referendums', 'D: all of the above'], answer: 'D', explanation: 'Elections, polls, and referendums all gauge public opinion.' },
  { id: 'gov93', year: 2024, topic: 'Public Opinion', difficulty: 'hard', question: 'One limitation of public opinion is that it', options: ['A: is always rational', 'B: can be manipulated by propaganda', 'C: reflects expert knowledge', 'D: is legally binding'], answer: 'B', explanation: 'Public opinion can be influenced and distorted by propaganda and misinformation.' },
  { id: 'gov94', year: 2024, topic: 'Constitution', difficulty: 'easy', question: 'A constitution that requires the same procedure for amending any of its provisions is described as', options: ['A: unitary', 'B: flexible', 'C: rigid', 'D: federal'], answer: 'B', explanation: 'A flexible constitution can be amended through ordinary legislative process.' },
  { id: 'gov95', year: 2024, topic: 'Political Systems', difficulty: 'medium', question: 'The concept of sovereignty means', options: ['A: absence of government', 'B: supreme power within a state', 'C: division of powers', 'D: rule by the few'], answer: 'B', explanation: 'Sovereignty is the ultimate authority within a given territory.' },
  { id: 'gov96', year: 2024, topic: 'Political Parties', difficulty: 'hard', question: 'The phenomenon where a single party dominates the political landscape for an extended period is known as', options: ['A: one-party state', 'B: dominant party system', 'C: two-party system', 'D: coalition government'], answer: 'B', explanation: 'A dominant party system allows other parties but one party dominates electorally.' },
  { id: 'gov97', year: 2024, topic: 'International Organizations', difficulty: 'medium', question: 'ECOWAS was established in', options: ['A: 1963', 'B: 1975', 'C: 1980', 'D: 1990'], answer: 'B', explanation: 'ECOWAS was founded in 1975 through the Treaty of Lagos.' },
  { id: 'gov98', year: 2024, topic: 'Citizenship', difficulty: 'medium', question: 'The right to vote and be voted for is known as', options: ['A: civil right', 'B: political right', 'C: economic right', 'D: social right'], answer: 'B', explanation: 'Political rights include participation in the political process, such as voting.' },
  { id: 'gov99', year: 2024, topic: 'Colonial Administration', difficulty: 'easy', question: 'The British colonial policy of governing through traditional institutions is called', options: ['A: assimilation', 'B: direct rule', 'C: indirect rule', 'D: association'], answer: 'C', explanation: 'Indirect rule used existing traditional structures to administer colonies.' },
  { id: 'gov100', year: 2024, topic: 'Public Administration', difficulty: 'hard', question: 'The budget prepared by the executive and approved by the legislature is the', options: ['A: capital budget', 'B: recurrent budget', 'C: appropriation bill', 'D: fiscal policy'], answer: 'C', explanation: 'The appropriation bill authorises government spending for a fiscal year.' },
  { id: 'gov101', year: 2024, topic: 'Judiciary', difficulty: 'hard', question: 'The legal principle that courts follow previous decisions is known as', options: ['A: stare decisis', 'B: obiter dictum', 'C: ratio decidendi', 'D: certiorari'], answer: 'A', explanation: 'Stare decisis means to stand by decided cases, ensuring consistency.' },
  { id: 'gov102', year: 2024, topic: 'Human Rights', difficulty: 'medium', question: 'Which international document first articulated fundamental human rights on a global scale?', options: ['A: Geneva Convention', 'B: Universal Declaration of Human Rights', 'C: Treaty of Westphalia', 'D: Magna Carta'], answer: 'B', explanation: 'The UDHR (1948) was the first global declaration of human rights.' },
  { id: 'gov103', year: 2024, topic: 'Elections & Electoral Systems', difficulty: 'medium', question: 'An election where voters choose candidates from their party list in order of preference is known as', options: ['A: primary election', 'B: general election', 'C: run-off election', 'D: recall election'], answer: 'A', explanation: 'A primary election determines a partys candidate for the general election.' },
  { id: 'gov104', year: 2024, topic: 'Public Opinion', difficulty: 'medium', question: 'A major channel through which public opinion is expressed in a democracy is', options: ['A: the military', 'B: the press', 'C: the monarchy', 'D: the cabinet'], answer: 'B', explanation: 'The press (media) is a key channel for expressing and shaping public opinion.' },
  { id: 'gov105', year: 2024, topic: 'Political Systems', difficulty: 'hard', question: 'A system where the state owns and controls the means of production is known as', options: ['A: capitalism', 'B: socialism', 'C: feudalism', 'D: mercantilism'], answer: 'B', explanation: 'Socialism advocates collective or state ownership of productive resources.' },
];

// LITERATURE
const jambLiteratureQuestions = [
  { id: 'lit21', year: 2024, topic: 'Prose', difficulty: 'easy', question: 'A novel is an example of', options: ['A: prose', 'B: poetry', 'C: drama', 'D: epic'], answer: 'A', explanation: 'The novel is a long fictional narrative prose work.' },
  { id: 'lit22', year: 2024, topic: 'Prose', difficulty: 'medium', question: 'The main character in a literary work is the', options: ['A: antagonist', 'B: protagonist', 'C: narrator', 'D: foil'], answer: 'B', explanation: 'The protagonist is the central character around whom the plot revolves.' },
  { id: 'lit23', year: 2024, topic: 'Prose', difficulty: 'medium', question: 'A short story differs from a novel mainly in its', options: ['A: theme', 'B: length and complexity', 'C: characters', 'D: setting'], answer: 'B', explanation: 'A short story is shorter and less complex than a novel.' },
  { id: 'lit24', year: 2024, topic: 'Prose', difficulty: 'hard', question: 'The character who opposes the protagonist is the', options: ['A: round character', 'B: antagonist', 'C: narrator', 'D: static character'], answer: 'B', explanation: 'The antagonist creates conflict for the protagonist.' },
  { id: 'lit25', year: 2024, topic: 'Prose', difficulty: 'easy', question: 'Which of the following is a sub-genre of prose?', options: ['A: Sonnet', 'B: Fable', 'C: Limerick', 'D: Haiku'], answer: 'B', explanation: 'A fable is a short prose narrative with a moral lesson.' },
  { id: 'lit26', year: 2024, topic: 'Poetry', difficulty: 'easy', question: 'A group of lines in a poem is called a', options: ['A: paragraph', 'B: stanza', 'C: scene', 'D: chapter'], answer: 'B', explanation: 'A stanza is the poetic equivalent of a paragraph in prose.' },
  { id: 'lit27', year: 2024, topic: 'Poetry', difficulty: 'medium', question: 'The repetition of initial consonant sounds in a line of poetry is called', options: ['A: assonance', 'B: alliteration', 'C: rhyme', 'D: onomatopoeia'], answer: 'B', explanation: 'Alliteration is the repetition of initial consonant sounds.' },
  { id: 'lit28', year: 2024, topic: 'Poetry', difficulty: 'medium', question: 'A sonnet has how many lines?', options: ['A: 10', 'B: 12', 'C: 14', 'D: 16'], answer: 'C', explanation: 'A sonnet traditionally consists of 14 lines.' },
  { id: 'lit29', year: 2024, topic: 'Poetry', difficulty: 'hard', question: 'The use of exaggeration for emphasis in poetry is called', options: ['A: metaphor', 'B: hyperbole', 'C: irony', 'D: simile'], answer: 'B', explanation: 'Hyperbole is deliberate exaggeration for effect.' },
  { id: 'lit30', year: 2024, topic: 'Poetry', difficulty: 'easy', question: 'A poem that tells a story is called a', options: ['A: lyric poem', 'B: narrative poem', 'C: ode', 'D: elegy'], answer: 'B', explanation: 'A narrative poem recounts a series of events or a story.' },
  { id: 'lit31', year: 2024, topic: 'Drama', difficulty: 'easy', question: 'A play is divided into', options: ['A: chapters', 'B: stanzas', 'C: acts and scenes', 'D: verses'], answer: 'C', explanation: 'Drama is structured into acts, which are subdivided into scenes.' },
  { id: 'lit32', year: 2024, topic: 'Drama', difficulty: 'medium', question: 'The person who writes a play is a', options: ['A: poet', 'B: novelist', 'C: playwright', 'D: narrator'], answer: 'C', explanation: 'A playwright is the author of a dramatic work.' },
  { id: 'lit33', year: 2024, topic: 'Drama', difficulty: 'medium', question: 'A tragedy typically ends with', options: ['A: a wedding', 'B: the death of the protagonist', 'C: a celebration', 'D: a resolution of all conflicts'], answer: 'B', explanation: 'Tragedy involves the downfall or death of the main character.' },
  { id: 'lit34', year: 2024, topic: 'Drama', difficulty: 'hard', question: 'A soliloquy is a speech where a character', options: ['A: speaks to another character', 'B: speaks alone on stage revealing inner thoughts', 'C: speaks to the audience directly', 'D: sings a song'], answer: 'B', explanation: 'A soliloquy reveals a characters private thoughts while alone on stage.' },
  { id: 'lit35', year: 2024, topic: 'Drama', difficulty: 'easy', question: 'A comedy is a play that ends', options: ['A: tragically', 'B: happily', 'C: ambiguously', 'D: with a moral lesson'], answer: 'B', explanation: 'Comedy typically ends happily, often with a marriage or reconciliation.' },
  { id: 'lit36', year: 2024, topic: 'Literary Terms', difficulty: 'easy', question: 'The term catharsis refers to', options: ['A: a comic relief', 'B: the purging of emotions in tragedy', 'C: the climax of a story', 'D: the introduction of characters'], answer: 'B', explanation: 'Catharsis is the emotional release experienced by the audience in a tragedy.' },
  { id: 'lit37', year: 2024, topic: 'Literary Terms', difficulty: 'medium', question: 'A foil is a character who', options: ['A: opposes the protagonist', 'B: contrasts with another character to highlight qualities', 'C: narrates the story', 'D: remains unchanged throughout'], answer: 'B', explanation: 'A foil highlights traits of another character through contrast.' },
  { id: 'lit38', year: 2024, topic: 'Literary Terms', difficulty: 'medium', question: 'Deus ex machina refers to', options: ['A: a sudden turn of events', 'B: an unrealistic or improbable resolution', 'C: a tragic flaw', 'D: a character analysis'], answer: 'B', explanation: 'Deus ex machina is an artificial or improbable device used to resolve a plot.' },
  { id: 'lit39', year: 2024, topic: 'Literary Terms', difficulty: 'hard', question: 'The term Bildungsroman describes a novel about', options: ['A: a journey', 'B: the education and development of the protagonist', 'C: a detective investigation', 'D: romantic love'], answer: 'B', explanation: 'Bildungsroman is a coming-of-age novel focusing on the protagonists growth.' },
  { id: 'lit40', year: 2024, topic: 'Literary Terms', difficulty: 'easy', question: 'A pun is a', options: ['A: figure of speech involving exaggeration', 'B: play on words with double meanings', 'C: repetition of vowel sounds', 'D: comparison using like or as'], answer: 'B', explanation: 'A pun exploits multiple meanings of a word for humorous effect.' },
  { id: 'lit41', year: 2024, topic: 'African Literature', difficulty: 'easy', question: 'Things Fall Apart was written by', options: ['A: Wole Soyinka', 'B: Chinua Achebe', 'C: Ngugi wa Thiongo', 'D: Ayi Kwei Armah'], answer: 'B', explanation: 'Chinua Achebe authored the iconic African novel Things Fall Apart.' },
  { id: 'lit42', year: 2024, topic: 'African Literature', difficulty: 'medium', question: 'The main character in Things Fall Apart is', options: ['A: Obierika', 'B: Okonkwo', 'C: Ikemefuna', 'D: Ezinma'], answer: 'B', explanation: 'Okonkwo is the protagonist of Achebes Things Fall Apart.' },
  { id: 'lit43', year: 2024, topic: 'African Literature', difficulty: 'medium', question: 'Wole Soyinka won the Nobel Prize for Literature in', options: ['A: 1985', 'B: 1986', 'C: 1987', 'D: 1988'], answer: 'B', explanation: 'Soyinka won the Nobel Prize in Literature in 1986.' },
  { id: 'lit44', year: 2024, topic: 'African Literature', difficulty: 'hard', question: 'The novel The River Between was written by', options: ['A: Chinua Achebe', 'B: Ngugi wa Thiongo', 'C: Ferdinand Oyono', 'D: Mariama Ba'], answer: 'B', explanation: 'Ngugi wa Thiongo wrote The River Between, set in colonial Kenya.' },
  { id: 'lit45', year: 2024, topic: 'African Literature', difficulty: 'easy', question: 'Which of the following is a play by Wole Soyinka?', options: ['A: Weep Not, Child', 'B: The Lion and the Jewel', 'C: So Long a Letter', 'D: The Beautyful Ones Are Not Yet Born'], answer: 'B', explanation: 'The Lion and the Jewel is a well-known play by Soyinka.' },
  { id: 'lit46', year: 2024, topic: 'Setting', difficulty: 'easy', question: 'The setting of a literary work refers to', options: ['A: the characters', 'B: the time and place of the action', 'C: the plot', 'D: the theme'], answer: 'B', explanation: 'Setting is the time and location where the story takes place.' },
  { id: 'lit47', year: 2024, topic: 'Setting', difficulty: 'medium', question: 'In Things Fall Apart, the primary setting is', options: ['A: urban Nigeria', 'B: pre-colonial Igbo village of Umuofia', 'C: colonial Lagos', 'D: the savannah grasslands'], answer: 'B', explanation: 'The novel is set in the Igbo village of Umuofia in pre-colonial Nigeria.' },
  { id: 'lit48', year: 2024, topic: 'Setting', difficulty: 'medium', question: 'The physical environment that influences the mood of a story is part of its', options: ['A: theme', 'B: plot', 'C: setting', 'D: characterization'], answer: 'C', explanation: 'Setting includes geographical location and atmosphere.' },
  { id: 'lit49', year: 2024, topic: 'Setting', difficulty: 'hard', question: 'The term local colour in literature refers to', options: ['A: the colour of the book cover', 'B: detailed depiction of regional characteristics', 'C: the use of colourful costumes', 'D: the lighting on stage'], answer: 'B', explanation: 'Local colour emphasises the unique customs, speech, and scenery of a region.' },
  { id: 'lit50', year: 2024, topic: 'Setting', difficulty: 'easy', question: 'A story set in the future is said to have a', options: ['A: historical setting', 'B: futuristic setting', 'C: contemporary setting', 'D: rural setting'], answer: 'B', explanation: 'A futuristic setting places events in a time yet to come.' },
  { id: 'lit51', year: 2024, topic: 'Characterization', difficulty: 'medium', question: 'A flat character is one who', options: ['A: is fully developed and complex', 'B: is one-dimensional and unchanging', 'C: changes during the story', 'D: narrates the plot'], answer: 'B', explanation: 'A flat character has limited traits and does not undergo significant change.' },
  { id: 'lit52', year: 2024, topic: 'Characterization', difficulty: 'medium', question: 'The method by which an author reveals a characters personality is called', options: ['A: plot', 'B: characterization', 'C: theme', 'D: narration'], answer: 'B', explanation: 'Characterisation is the technique used to create and develop characters.' },
  { id: 'lit53', year: 2024, topic: 'Characterization', difficulty: 'hard', question: 'Indirect characterization reveals character through', options: ['A: direct description by the author', 'B: actions, speech, and thoughts of the character', 'C: the title of the work', 'D: the setting only'], answer: 'B', explanation: 'Indirect characterisation shows character through behaviour, dialogue, and interaction.' },
  { id: 'lit54', year: 2024, topic: 'Characterization', difficulty: 'easy', question: 'A round character is', options: ['A: static and predictable', 'B: complex and multi-dimensional', 'C: a minor character', 'D: a stock character'], answer: 'B', explanation: 'A round character is fully developed with complex traits and motivations.' },
  { id: 'lit55', year: 2024, topic: 'Characterization', difficulty: 'medium', question: 'A stock character is', options: ['A: a unique individual', 'B: a stereotypical character easily recognised', 'C: the narrator', 'D: the antagonist'], answer: 'B', explanation: 'A stock character is a familiar stereotype, like the wise old man.' },
  { id: 'lit56', year: 2024, topic: 'Theme', difficulty: 'easy', question: 'The theme of a literary work is its', options: ['A: central idea or message', 'B: main character', 'C: setting', 'D: plot summary'], answer: 'A', explanation: 'Theme is the underlying message or central idea of a work.' },
  { id: 'lit57', year: 2024, topic: 'Theme', difficulty: 'medium', question: 'One major theme in Things Fall Apart is', options: ['A: the joy of urbanisation', 'B: the clash between tradition and change', 'C: the benefits of colonialism', 'D: the simplicity of rural life'], answer: 'B', explanation: 'Achebe explores the conflict between Igbo tradition and colonial influence.' },
  { id: 'lit58', year: 2024, topic: 'Theme', difficulty: 'medium', question: 'A work that explicitly teaches a moral lesson is said to have a', options: ['A: didactic theme', 'B: universal theme', 'C: minor theme', 'D: implicit theme'], answer: 'A', explanation: 'Didactic literature aims to instruct or teach a moral lesson.' },
  { id: 'lit59', year: 2024, topic: 'Theme', difficulty: 'hard', question: 'When a theme recurs across different works by the same author, it is called a', options: ['A: motif', 'B: leitmotif', 'C: message', 'D: thesis'], answer: 'A', explanation: 'A motif is a recurring element or theme in a body of work.' },
  { id: 'lit60', year: 2024, topic: 'Theme', difficulty: 'easy', question: 'The theme of a poem is often expressed through', options: ['A: its title only', 'B: imagery, symbols, and figurative language', 'C: the poets biography', 'D: the rhyme scheme'], answer: 'B', explanation: 'Poetic devices convey the theme indirectly.' },
  { id: 'lit61', year: 2024, topic: 'Literary Appreciation', difficulty: 'medium', question: 'The readers emotional response to a literary work is the', options: ['A: plot', 'B: mood', 'C: theme', 'D: tone'], answer: 'B', explanation: 'Mood is the atmosphere or emotional effect on the reader.' },
  { id: 'lit62', year: 2024, topic: 'Literary Appreciation', difficulty: 'medium', question: 'The attitude of the author towards the subject is called', options: ['A: mood', 'B: tone', 'C: style', 'D: theme'], answer: 'B', explanation: 'Tone reflects the authors attitude toward the subject or audience.' },
  { id: 'lit63', year: 2024, topic: 'Literary Appreciation', difficulty: 'hard', question: 'The term verisimilitude in literary appreciation means', options: ['A: the use of verse', 'B: the appearance of truth in fiction', 'C: the climax of the story', 'D: the authors biography'], answer: 'B', explanation: 'Verisimilitude is the quality of seeming true or realistic.' },
  { id: 'lit64', year: 2024, topic: 'Literary Appreciation', difficulty: 'easy', question: 'The style of an author is characterised by all EXCEPT', options: ['A: word choice', 'B: sentence structure', 'C: plot summary', 'D: use of figurative language'], answer: 'C', explanation: 'Style involves how something is written, not a summary of events.' },
  { id: 'lit65', year: 2024, topic: 'Literary Appreciation', difficulty: 'medium', question: 'The phrase the curtains of the night refers to', options: ['A: simile', 'B: metaphor', 'C: personification', 'D: oxymoron'], answer: 'B', explanation: 'It is a metaphor comparing night to curtains.' },
  { id: 'lit66', year: 2024, topic: 'Figures of Speech', difficulty: 'easy', question: 'A simile compares two things using', options: ['A: like or as', 'B: but or however', 'C: and or or', 'D: if or then'], answer: 'A', explanation: 'Simile uses like or as to make explicit comparisons.' },
  { id: 'lit67', year: 2024, topic: 'Figures of Speech', difficulty: 'easy', question: 'The expression He is a lion in battle is an example of', options: ['A: simile', 'B: metaphor', 'C: personification', 'D: hyperbole'], answer: 'B', explanation: 'It directly equates the man to a lion, a metaphor.' },
  { id: 'lit68', year: 2024, topic: 'Figures of Speech', difficulty: 'medium', question: 'Giving human qualities to inanimate objects is called', options: ['A: metaphor', 'B: personification', 'C: simile', 'D: apostrophe'], answer: 'B', explanation: 'Personification attributes human traits to non-human entities.' },
  { id: 'lit69', year: 2024, topic: 'Figures of Speech', difficulty: 'medium', question: 'The use of words that imitate natural sounds is called', options: ['A: alliteration', 'B: onomatopoeia', 'C: assonance', 'D: consonance'], answer: 'B', explanation: 'Onomatopoeia includes words like buzz, hiss, and boom.' },
  { id: 'lit70', year: 2024, topic: 'Figures of Speech', difficulty: 'hard', question: 'An oxymoron combines', options: ['A: similar ideas', 'B: contradictory terms', 'C: rhyming words', 'D: long and short syllables'], answer: 'B', explanation: 'Oxymoron pairs opposite words, e.g., bitter-sweet.' },
  { id: 'lit71', year: 2024, topic: 'Figures of Speech', difficulty: 'easy', question: 'A figure of speech that addresses an absent person as if present is', options: ['A: apostrophe', 'B: metaphor', 'C: simile', 'D: irony'], answer: 'A', explanation: 'Apostrophe directly addresses an absent person or abstract idea.' },
  { id: 'lit72', year: 2024, topic: 'Plot', difficulty: 'medium', question: 'The sequence of events in a story is the', options: ['A: theme', 'B: plot', 'C: setting', 'D: character'], answer: 'B', explanation: 'Plot is the ordered sequence of events in a narrative.' },
  { id: 'lit73', year: 2024, topic: 'Plot', difficulty: 'medium', question: 'The highest point of tension in a plot is the', options: ['A: exposition', 'B: rising action', 'C: climax', 'D: resolution'], answer: 'C', explanation: 'The climax is the turning point with maximum conflict.' },
  { id: 'lit74', year: 2024, topic: 'Plot', difficulty: 'hard', question: 'The part of a plot where conflicts are introduced and developed is the', options: ['A: exposition', 'B: rising action', 'C: falling action', 'D: denouement'], answer: 'B', explanation: 'Rising action builds suspense through developing conflicts.' },
  { id: 'lit75', year: 2024, topic: 'Plot', difficulty: 'easy', question: 'The conclusion of a story where loose ends are tied is the', options: ['A: climax', 'B: rising action', 'C: denouement', 'D: inciting incident'], answer: 'C', explanation: 'The denouement resolves remaining issues after the climax.' },
  { id: 'lit76', year: 2024, topic: 'Plot', difficulty: 'medium', question: 'An episodic plot is characterised by', options: ['A: a single continuous storyline', 'B: a series of loosely connected events', 'C: a circular narrative structure', 'D: non-linear time'], answer: 'B', explanation: 'Episodic plots consist of discrete episodes strung together.' },
  { id: 'lit77', year: 2024, topic: 'Narrative Technique', difficulty: 'medium', question: 'A story told by one of its characters using I is in the', options: ['A: first-person point of view', 'B: second-person point of view', 'C: third-person omniscient', 'D: third-person limited'], answer: 'A', explanation: 'First-person uses I and the narrator is a character in the story.' },
  { id: 'lit78', year: 2024, topic: 'Narrative Technique', difficulty: 'medium', question: 'An all-knowing narrator who knows the thoughts of all characters uses the', options: ['A: first-person point of view', 'B: third-person omniscient', 'C: third-person limited', 'D: objective point of view'], answer: 'B', explanation: 'Omniscient narration knows everything about all characters.' },
  { id: 'lit79', year: 2024, topic: 'Narrative Technique', difficulty: 'hard', question: 'A flashback is a narrative technique that', options: ['A: moves the story forward in time', 'B: interrupts the present to show past events', 'C: changes the narrator', 'D: reveals the future'], answer: 'B', explanation: 'Flashback interrupts chronological order to present earlier events.' },
  { id: 'lit80', year: 2024, topic: 'Narrative Technique', difficulty: 'easy', question: 'An unreliable narrator is one who', options: ['A: cannot be trusted to give an accurate account', 'B: narrates from multiple perspectives', 'C: always tells the truth', 'D: narrates in third person'], answer: 'A', explanation: 'An unreliable narrator distorts or misrepresents the truth.' },
  { id: 'lit81', year: 2024, topic: 'Narrative Technique', difficulty: 'hard', question: 'A frame narrative is a story that', options: ['A: has no plot', 'B: contains another story within it', 'C: is told in verse', 'D: is set in the distant past'], answer: 'B', explanation: 'A frame narrative encloses one or more inner stories.' },
  { id: 'lit82', year: 2024, topic: 'Mood & Tone', difficulty: 'easy', question: 'The feeling or atmosphere created in a literary work is the', options: ['A: tone', 'B: mood', 'C: theme', 'D: style'], answer: 'B', explanation: 'Mood refers to the emotional atmosphere experienced by the reader.' },
  { id: 'lit83', year: 2024, topic: 'Mood & Tone', difficulty: 'medium', question: 'A sombre mood in a text can be created through', options: ['A: bright imagery and humour', 'B: dark imagery and slow pacing', 'C: fast-paced action', 'D: comic relief'], answer: 'B', explanation: 'Dark imagery and slow pacing evoke a sombre, serious mood.' },
  { id: 'lit84', year: 2024, topic: 'Mood & Tone', difficulty: 'medium', question: 'The tone of a satirical work is often', options: ['A: celebratory', 'B: critical and mocking', 'C: neutral', 'D: melancholic'], answer: 'B', explanation: 'Satire uses humour, irony, or exaggeration to criticise.' },
  { id: 'lit85', year: 2024, topic: 'Mood & Tone', difficulty: 'hard', question: 'When an author uses a formal tone, the diction is likely', options: ['A: colloquial', 'B: elevated and sophisticated', 'C: slang-filled', 'D: simple and childish'], answer: 'B', explanation: 'Formal tone uses elevated, precise, and complex language.' },
  { id: 'lit86', year: 2024, topic: 'Style', difficulty: 'medium', question: 'The distinctive way an author uses language is called', options: ['A: theme', 'B: style', 'C: plot', 'D: genre'], answer: 'B', explanation: 'Style is the authors unique manner of expression.' },
  { id: 'lit87', year: 2024, topic: 'Style', difficulty: 'medium', question: 'A writer known for using long, complex sentences is described as having an', options: ['A: elliptical style', 'B: periodic style', 'C: epigrammatic style', 'D: colloquial style'], answer: 'B', explanation: 'Periodic style delays the main clause for effect, using long sentences.' },
  { id: 'lit88', year: 2024, topic: 'Style', difficulty: 'hard', question: 'The use of short, concise, and witty statements is known as', options: ['A: bombast', 'B: epigrammatic style', 'C: verbose style', 'D: ornate style'], answer: 'B', explanation: 'Epigrammatic style is marked by brevity and wit.' },
  { id: 'lit89', year: 2024, topic: 'Style', difficulty: 'easy', question: 'An authors choice of words is called', options: ['A: syntax', 'B: diction', 'C: tone', 'D: mood'], answer: 'B', explanation: 'Diction refers to the selection of words in writing.' },
  { id: 'lit90', year: 2024, topic: 'Style', difficulty: 'medium', question: 'The arrangement of words and phrases to create well-formed sentences is', options: ['A: diction', 'B: syntax', 'C: imagery', 'D: rhythm'], answer: 'B', explanation: 'Syntax governs sentence structure and word order.' },
  { id: 'lit91', year: 2024, topic: 'Prose', difficulty: 'hard', question: 'A novel of manners examines the', options: ['A: military strategies', 'B: social customs and conventions of a class', 'C: supernatural elements', 'D: adventure and exploration'], answer: 'B', explanation: 'The novel of manners focuses on the social etiquette of a particular group.' },
  { id: 'lit92', year: 2024, topic: 'Poetry', difficulty: 'hard', question: 'A limerick has a rhyme scheme of', options: ['A: ABAB', 'B: AABBA', 'C: ABBA', 'D: ABCABC'], answer: 'B', explanation: 'The limerick follows an AABBA rhyme scheme.' },
  { id: 'lit93', year: 2024, topic: 'Drama', difficulty: 'medium', question: 'The characters who comment on the action in a Greek chorus are called the', options: ['A: antagonists', 'B: chorus', 'C: narrators', 'D: foils'], answer: 'B', explanation: 'The chorus in Greek drama comments on events and provides background.' },
  { id: 'lit94', year: 2024, topic: 'Literary Terms', difficulty: 'medium', question: 'A paradox is a statement that', options: ['A: is obviously true', 'B: appears contradictory but contains truth', 'C: uses exaggeration', 'D: compares two unlike things'], answer: 'B', explanation: 'A paradox seems self-contradictory but reveals a deeper truth.' },
  { id: 'lit95', year: 2024, topic: 'African Literature', difficulty: 'medium', question: 'The central conflict in Ngugi wa Thiongos Weep Not, Child is', options: ['A: the Mau Mau uprising', 'B: urban poverty', 'C: tribal marriage customs', 'D: slavery'], answer: 'A', explanation: 'The novel is set against the backdrop of the Mau Mau struggle in Kenya.' },
  { id: 'lit96', year: 2024, topic: 'Setting', difficulty: 'hard', question: 'The setting of George Orwells 1984 is', options: ['A: a utopian society', 'B: a dystopian totalitarian state', 'C: a medieval kingdom', 'D: Victorian England'], answer: 'B', explanation: '1984 depicts a dystopian future under totalitarian rule.' },
  { id: 'lit97', year: 2024, topic: 'Characterization', difficulty: 'hard', question: 'A dynamic character is one who', options: ['A: remains unchanged throughout', 'B: undergoes significant internal change', 'C: is a minor character', 'D: represents a stereotype'], answer: 'B', explanation: 'A dynamic character develops and changes during the story.' },
  { id: 'lit98', year: 2024, topic: 'Theme', difficulty: 'medium', question: 'The theme of pride and prejudice in Jane Austens novel relates to', options: ['A: war and peace', 'B: social class and marriage', 'C: crime and punishment', 'D: exploration and discovery'], answer: 'B', explanation: 'Austens novel critiques social class and courtship in 19th-century England.' },
  { id: 'lit99', year: 2024, topic: 'Literary Appreciation', difficulty: 'hard', question: 'The literary device where the audience knows something the characters do not is', options: ['A: verbal irony', 'B: dramatic irony', 'C: situational irony', 'D: cosmic irony'], answer: 'B', explanation: 'Dramatic irony occurs when the audience knows more than the characters.' },
  { id: 'lit100', year: 2024, topic: 'Figures of Speech', difficulty: 'medium', question: 'The repetition of vowel sounds within nearby words is', options: ['A: alliteration', 'B: assonance', 'C: consonance', 'D: rhyme'], answer: 'B', explanation: 'Assonance repeats vowel sounds, e.g., fleet feet sweep by.' },
  { id: 'lit101', year: 2024, topic: 'Plot', difficulty: 'hard', question: 'The inciting incident is the event that', options: ['A: concludes the story', 'B: sets the main conflict in motion', 'C: introduces the setting', 'D: develops secondary characters'], answer: 'B', explanation: 'The inciting incident triggers the central conflict of the plot.' },
  { id: 'lit102', year: 2024, topic: 'Narrative Technique', difficulty: 'medium', question: 'A story told using you is written in the', options: ['A: first person', 'B: second person', 'C: third person', 'D: omniscient perspective'], answer: 'B', explanation: 'Second-person narration addresses the reader directly as you.' },
  { id: 'lit103', year: 2024, topic: 'Mood & Tone', difficulty: 'medium', question: 'An elegiac tone is characterised by', options: ['A: joy and celebration', 'B: sorrow and lamentation', 'C: humour and wit', 'D: anger and indignation'], answer: 'B', explanation: 'An elegiac tone expresses sadness or mourning.' },
  { id: 'lit104', year: 2024, topic: 'Style', difficulty: 'hard', question: 'A telegraphic style is marked by', options: ['A: elaborate descriptions', 'B: very short, clipped sentences', 'C: complex subordinate clauses', 'D: flowery language'], answer: 'B', explanation: 'Telegraphic style uses minimal words for direct, concise expression.' },
  { id: 'lit105', year: 2024, topic: 'Poetry', difficulty: 'medium', question: 'A poem without a fixed rhyme or meter is called', options: ['A: sonnet', 'B: free verse', 'C: blank verse', 'D: haiku'], answer: 'B', explanation: 'Free verse has no regular rhyme scheme or metrical pattern.' },
];

// COMMERCE
const jambCommerceQuestions = [
  { id: 'com19', year: 2024, topic: 'Trade', difficulty: 'easy', question: 'The buying and selling of goods and services is known as', options: ['A: production', 'B: trade', 'C: consumption', 'D: distribution'], answer: 'B', explanation: 'Trade is the exchange of goods and services between parties.' },
  { id: 'com20', year: 2024, topic: 'Trade', difficulty: 'easy', question: 'Trade between two or more countries is called', options: ['A: home trade', 'B: international trade', 'C: wholesale trade', 'D: retail trade'], answer: 'B', explanation: 'International trade involves the exchange of goods across national borders.' },
  { id: 'com21', year: 2024, topic: 'Trade', difficulty: 'medium', question: 'The difference between a countrys exports and imports is its', options: ['A: balance of trade', 'B: balance of payments', 'C: national income', 'D: terms of trade'], answer: 'A', explanation: 'Balance of trade is the difference between the value of exports and imports.' },
  { id: 'com22', year: 2024, topic: 'Trade', difficulty: 'medium', question: 'A middleman who buys in bulk and sells in smaller quantities to retailers is a', options: ['A: wholesaler', 'B: retailer', 'C: consumer', 'D: producer'], answer: 'A', explanation: 'Wholesalers purchase large quantities and distribute to retailers.' },
  { id: 'com23', year: 2024, topic: 'Trade', difficulty: 'hard', question: 'A country has a comparative advantage in producing a good if it', options: ['A: produces it at the lowest absolute cost', 'B: produces it at a lower opportunity cost', 'C: has the largest market share', 'D: exports the most of that good'], answer: 'B', explanation: 'Comparative advantage is based on lower opportunity cost in production.' },
  { id: 'com24', year: 2024, topic: 'Trade', difficulty: 'easy', question: 'The term entrepot trade refers to', options: ['A: trade within a country', 'B: importing goods for re-export', 'C: trade in agricultural products', 'D: trade between two countries directly'], answer: 'B', explanation: 'Entrepot trade involves importing goods and re-exporting them, often with some processing.' },
  { id: 'com25', year: 2024, topic: 'Trade', difficulty: 'medium', question: 'A tariff is a tax imposed on', options: ['A: income', 'B: imported goods', 'C: exported goods', 'D: property'], answer: 'B', explanation: 'Tariffs are taxes on imports, used to protect domestic industries.' },
  { id: 'com26', year: 2024, topic: 'Trade', difficulty: 'hard', question: 'The document that gives details of goods shipped and serves as a contract of carriage is the', options: ['A: bill of lading', 'B: invoice', 'C: letter of credit', 'D: certificate of origin'], answer: 'A', explanation: 'A bill of lading is a shipping document and contract between shipper and carrier.' },
  { id: 'com27', year: 2024, topic: 'Advertising', difficulty: 'easy', question: 'Advertising is a form of', options: ['A: production', 'B: promotion', 'C: pricing', 'D: distribution'], answer: 'B', explanation: 'Advertising is a promotional activity to inform and persuade consumers.' },
  { id: 'com28', year: 2024, topic: 'Advertising', difficulty: 'medium', question: 'The main purpose of advertising is to', options: ['A: reduce production cost', 'B: increase sales and create demand', 'C: eliminate competition', 'D: reduce taxes'], answer: 'B', explanation: 'Advertising aims to boost sales by informing and persuading potential buyers.' },
  { id: 'com29', year: 2024, topic: 'Advertising', difficulty: 'medium', question: 'A billboard is an example of', options: ['A: direct advertising', 'B: outdoor advertising', 'C: online advertising', 'D: print advertising'], answer: 'B', explanation: 'Billboards are outdoor advertising media placed in public locations.' },
  { id: 'com30', year: 2024, topic: 'Advertising', difficulty: 'hard', question: 'The slogan or catchphrase used repeatedly in advertising is called a', options: ['A: logo', 'B: jingle', 'C: brand name', 'D: tagline'], answer: 'D', explanation: 'A tagline is a memorable phrase used consistently in advertising.' },
  { id: 'com31', year: 2024, topic: 'Advertising', difficulty: 'easy', question: 'Advertising through newspapers is classified as', options: ['A: broadcast advertising', 'B: print advertising', 'C: outdoor advertising', 'D: digital advertising'], answer: 'B', explanation: 'Newspaper advertising falls under print media.' },
  { id: 'com32', year: 2024, topic: 'Advertising', difficulty: 'medium', question: 'The advertising medium with the widest reach is generally', options: ['A: radio', 'B: television', 'C: magazine', 'D: direct mail'], answer: 'B', explanation: 'Television reaches a broad, diverse audience simultaneously.' },
  { id: 'com33', year: 2024, topic: 'Insurance', difficulty: 'easy', question: 'Insurance is a contract of', options: ['A: sale', 'B: indemnity', 'C: partnership', 'D: agency'], answer: 'B', explanation: 'Insurance indemnifies the insured against specified losses.' },
  { id: 'com34', year: 2024, topic: 'Insurance', difficulty: 'medium', question: 'The person who is protected under an insurance policy is the', options: ['A: insurer', 'B: insured', 'C: broker', 'D: agent'], answer: 'B', explanation: 'The insured is the party covered by the insurance policy.' },
  { id: 'com35', year: 2024, topic: 'Insurance', difficulty: 'medium', question: 'The premium in insurance refers to the', options: ['A: amount paid to the insured after a loss', 'B: amount paid by the insured for coverage', 'C: profit of the insurance company', 'D: penalty for late payment'], answer: 'B', explanation: 'A premium is the consideration paid by the insured for insurance cover.' },
  { id: 'com36', year: 2024, topic: 'Insurance', difficulty: 'hard', question: 'The principle of subrogation in insurance means', options: ['A: the insured can claim from multiple insurers', 'B: the insurer steps into the shoes of the insured after settlement', 'C: both parties must act in utmost good faith', 'D: the insured must have an insurable interest'], answer: 'B', explanation: 'Subrogation allows the insurer to pursue recovery from third parties after paying a claim.' },
  { id: 'com37', year: 2024, topic: 'Insurance', difficulty: 'easy', question: 'Life insurance is also known as', options: ['A: general insurance', 'B: assurance', 'C: indemnity insurance', 'D: property insurance'], answer: 'B', explanation: 'Life insurance is called assurance because the event (death) is certain.' },
  { id: 'com38', year: 2024, topic: 'Insurance', difficulty: 'medium', question: 'The type of insurance that covers goods in transit is', options: ['A: fire insurance', 'B: marine insurance', 'C: life insurance', 'D: liability insurance'], answer: 'B', explanation: 'Marine insurance covers loss or damage to goods during transportation.' },
  { id: 'com39', year: 2024, topic: 'Insurance', difficulty: 'hard', question: 'Motor vehicle insurance is compulsory in Nigeria under the', options: ['A: Insurance Act 2003', 'B: Companies and Allied Matters Act', 'C: Labour Act', 'D: Pension Reform Act'], answer: 'A', explanation: 'The Insurance Act 2003 mandates third-party motor insurance.' },
  { id: 'com40', year: 2024, topic: 'Business Units', difficulty: 'easy', question: 'A business owned by one person is called a', options: ['A: partnership', 'B: sole proprietorship', 'C: corporation', 'D: cooperative'], answer: 'B', explanation: 'A sole proprietorship is owned and run by a single individual.' },
  { id: 'com41', year: 2024, topic: 'Business Units', difficulty: 'medium', question: 'A major disadvantage of a sole proprietorship is', options: ['A: limited liability', 'B: unlimited liability', 'C: ease of formation', 'D: quick decision-making'], answer: 'B', explanation: 'The owner bears unlimited personal liability for business debts.' },
  { id: 'com42', year: 2024, topic: 'Business Units', difficulty: 'medium', question: 'A partnership deed is a', options: ['A: verbal agreement between partners', 'B: written agreement outlining partnership terms', 'C: government license', 'D: bank document'], answer: 'B', explanation: 'A partnership deed is a formal written document regulating partnership operations.' },
  { id: 'com43', year: 2024, topic: 'Business Units', difficulty: 'hard', question: 'The minimum number of members required to form a public limited company in Nigeria is', options: ['A: 2', 'B: 5', 'C: 7', 'D: 10'], answer: 'A', explanation: 'Under CAMA, a public company requires a minimum of two members.' },
  { id: 'com44', year: 2024, topic: 'Business Units', difficulty: 'easy', question: 'Shareholders of a company are its', options: ['A: creditors', 'B: owners', 'C: employees', 'D: managers'], answer: 'B', explanation: 'Shareholders are the owners of a company by virtue of holding shares.' },
  { id: 'com45', year: 2024, topic: 'Business Units', difficulty: 'medium', question: 'The liability of shareholders in a public limited company is', options: ['A: unlimited', 'B: limited to the value of shares held', 'C: limited to their personal assets', 'D: joint and several'], answer: 'B', explanation: 'Shareholders liability is limited to the unpaid amount on their shares.' },
  { id: 'com46', year: 2024, topic: 'Business Units', difficulty: 'hard', question: 'A cooperative society is formed primarily for the purpose of', options: ['A: profit maximisation', 'B: mutual benefit and self-help', 'C: acquiring political power', 'D: exporting goods'], answer: 'B', explanation: 'Cooperatives are voluntary associations for mutual economic benefit.' },
  { id: 'com47', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'easy', question: 'The buying and selling of goods over the internet is called', options: ['A: mail order', 'B: e-commerce', 'C: telemarketing', 'D: retailing'], answer: 'B', explanation: 'E-commerce refers to commercial transactions conducted electronically.' },
  { id: 'com48', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'medium', question: 'A major advantage of e-commerce is', options: ['A: limited market reach', 'B: 24/7 availability', 'C: high overhead costs', 'D: delayed transactions'], answer: 'B', explanation: 'E-commerce platforms operate round the clock without closing.' },
  { id: 'com49', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'medium', question: 'B2B e-commerce refers to transactions between', options: ['A: business and consumer', 'B: business and business', 'C: consumer and consumer', 'D: government and citizen'], answer: 'B', explanation: 'B2B involves online transactions between businesses.' },
  { id: 'com50', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'hard', question: 'A major challenge facing e-commerce in Nigeria is', options: ['A: high internet penetration', 'B: poor logistics infrastructure', 'C: excessive government regulation', 'D: low population density'], answer: 'B', explanation: 'Poor transportation and delivery infrastructure hinder e-commerce growth.' },
  { id: 'com51', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'easy', question: 'An example of an e-commerce platform is', options: ['A: a supermarket', 'B: Amazon', 'C: a wholesale market', 'D: a shopping mall'], answer: 'B', explanation: 'Amazon is a leading global e-commerce website.' },
  { id: 'com52', year: 2024, topic: 'Money & Finance', difficulty: 'easy', question: 'Money serves as all of the following EXCEPT', options: ['A: medium of exchange', 'B: store of value', 'C: unit of account', 'D: factor of production'], answer: 'D', explanation: 'Money functions as a medium of exchange, store of value, and unit of account, but is not a factor of production (land, labour, capital, entrepreneurship).' },
  { id: 'com53', year: 2024, topic: 'Money & Finance', difficulty: 'medium', question: 'The central bank of Nigeria is responsible for', options: ['A: printing currency and controlling monetary policy', 'B: granting loans to individuals', 'C: operating current accounts for customers', 'D: issuing insurance policies'], answer: 'A', explanation: 'The CBN regulates the financial system and manages monetary policy.' },
  { id: 'com54', year: 2024, topic: 'Money & Finance', difficulty: 'medium', question: 'A cheque that cannot be cashed over the counter but paid into an account is a', options: ['A: bearer cheque', 'B: crossed cheque', 'C: open cheque', 'D: blank cheque'], answer: 'B', explanation: 'A crossed cheque can only be deposited into a bank account, not cashed directly.' },
  { id: 'com55', year: 2024, topic: 'Money & Finance', difficulty: 'hard', question: 'Monetary policy aimed at reducing inflation involves', options: ['A: increasing money supply', 'B: increasing interest rates', 'C: reducing taxes', 'D: increasing government spending'], answer: 'B', explanation: 'Higher interest rates reduce borrowing and spending, curbing inflation.' },
  { id: 'com56', year: 2024, topic: 'Money & Finance', difficulty: 'easy', question: 'A savings account is best for', options: ['A: daily transactions', 'B: long-term savings and earning interest', 'C: business loans', 'D: stock trading'], answer: 'B', explanation: 'Savings accounts are designed for safe storage of funds with interest earnings.' },
  { id: 'com57', year: 2024, topic: 'Money & Finance', difficulty: 'medium', question: 'The rate at which the central bank lends to commercial banks is the', options: ['A: bank rate', 'B: savings rate', 'C: treasury bill rate', 'D: prime lending rate'], answer: 'A', explanation: 'The bank rate (or discount rate) is the rate at which the central bank lends to commercial banks.' },
  { id: 'com58', year: 2024, topic: 'Transportation', difficulty: 'easy', question: 'The fastest mode of transportation is', options: ['A: road', 'B: rail', 'C: air', 'D: water'], answer: 'C', explanation: 'Air transport is the fastest mode of moving goods and people.' },
  { id: 'com59', year: 2024, topic: 'Transportation', difficulty: 'medium', question: 'The most flexible mode of transport for door-to-door delivery is', options: ['A: railway', 'B: road', 'C: air', 'D: pipeline'], answer: 'B', explanation: 'Road transport provides the greatest flexibility for door-to-door service.' },
  { id: 'com60', year: 2024, topic: 'Transportation', difficulty: 'medium', question: 'A major disadvantage of rail transport is its', options: ['A: speed', 'B: lack of flexibility and high capital cost', 'C: limited carrying capacity', 'D: high fuel consumption per tonne'], answer: 'B', explanation: 'Rail requires fixed tracks and high infrastructure investment.' },
  { id: 'com61', year: 2024, topic: 'Transportation', difficulty: 'hard', question: 'The document used in clearing goods through customs is the', options: ['A: bill of lading', 'B: customs declaration form', 'C: certificate of incorporation', 'D: deed of partnership'], answer: 'B', explanation: 'A customs declaration form provides details of goods for import/export clearance.' },
  { id: 'com62', year: 2024, topic: 'Transportation', difficulty: 'easy', question: 'The cheapest mode of transport for bulky goods over long distances is', options: ['A: air', 'B: road', 'C: water', 'D: pipeline'], answer: 'C', explanation: 'Water transport is the most economical for heavy, bulky cargo over long distances.' },
  { id: 'com63', year: 2024, topic: 'Transportation', difficulty: 'medium', question: 'The cost of transporting goods from the factory to the consumer is part of', options: ['A: production cost', 'B: distribution cost', 'C: marketing cost', 'D: administrative cost'], answer: 'B', explanation: 'Distribution cost includes moving goods from producer to consumer.' },
  { id: 'com64', year: 2024, topic: 'Warehousing', difficulty: 'easy', question: 'The storage of goods from the time of production to the time of consumption is called', options: ['A: warehousing', 'B: transportation', 'C: advertising', 'D: insurance'], answer: 'A', explanation: 'Warehousing bridges the time gap between production and consumption.' },
  { id: 'com65', year: 2024, topic: 'Warehousing', difficulty: 'medium', question: 'A warehouse that stores goods owned by different people and issues a receipt is a', options: ['A: public warehouse', 'B: private warehouse', 'C: bonded warehouse', 'D: cold storage'], answer: 'A', explanation: 'Public warehouses store goods for multiple clients and issue warehouse receipts.' },
  { id: 'com66', year: 2024, topic: 'Warehousing', difficulty: 'medium', question: 'Bonded warehouses are used for storing', options: ['A: perishable goods', 'B: imported goods before customs duty is paid', 'C: heavy machinery', 'D: agricultural produce'], answer: 'B', explanation: 'Bonded warehouses store imported goods until customs duties are settled.' },
  { id: 'com67', year: 2024, topic: 'Warehousing', difficulty: 'hard', question: 'The document issued by a warehouse indicating ownership of stored goods is a', options: ['A: warehouse receipt', 'B: invoice', 'C: delivery note', 'D: waybill'], answer: 'A', explanation: 'A warehouse receipt is a document of title to goods stored in a warehouse.' },
  { id: 'com68', year: 2024, topic: 'Warehousing', difficulty: 'easy', question: 'A major benefit of warehousing is', options: ['A: increasing transportation cost', 'B: stabilising prices through storage', 'C: reducing product variety', 'D: eliminating the need for insurance'], answer: 'B', explanation: 'Warehousing helps regulate supply and stabilise market prices.' },
  { id: 'com69', year: 2024, topic: 'Marketing', difficulty: 'easy', question: 'The marketing mix consists of all the following EXCEPT', options: ['A: product', 'B: price', 'C: profit', 'D: promotion'], answer: 'C', explanation: 'The 4Ps of marketing are Product, Price, Place, and Promotion.' },
  { id: 'com70', year: 2024, topic: 'Marketing', difficulty: 'medium', question: 'Market segmentation involves dividing the market based on', options: ['A: profit margins only', 'B: demographic, geographic, psychographic, or behavioural factors', 'C: the number of competitors', 'D: government regulations'], answer: 'B', explanation: 'Market segmentation groups consumers based on shared characteristics.' },
  { id: 'com71', year: 2024, topic: 'Marketing', difficulty: 'medium', question: 'Branding is important because it', options: ['A: reduces production cost', 'B: differentiates a product from competitors', 'C: eliminates the need for advertising', 'D: guarantees product quality'], answer: 'B', explanation: 'Branding distinguishes a product in the marketplace.' },
  { id: 'com72', year: 2024, topic: 'Marketing', difficulty: 'hard', question: 'The process of setting a price below competitors to gain market share is called', options: ['A: skimming pricing', 'B: penetration pricing', 'C: cost-plus pricing', 'D: premium pricing'], answer: 'B', explanation: 'Penetration pricing sets low initial prices to attract customers and gain market share.' },
  { id: 'com73', year: 2024, topic: 'Marketing', difficulty: 'easy', question: 'The place element of the marketing mix deals with', options: ['A: product design', 'B: distribution channels', 'C: promotional offers', 'D: pricing strategy'], answer: 'B', explanation: 'Place refers to how products reach consumers through distribution channels.' },
  { id: 'com74', year: 2024, topic: 'Consumer Protection', difficulty: 'easy', question: 'The agency responsible for consumer protection in Nigeria is', options: ['A: NAFDAC', 'B: FCCPC', 'C: CBN', 'D: NSE'], answer: 'B', explanation: 'The Federal Competition and Consumer Protection Commission (FCCPC) protects consumers.' },
  { id: 'com75', year: 2024, topic: 'Consumer Protection', difficulty: 'medium', question: 'The right of consumers to be informed means they should', options: ['A: receive full product information before purchase', 'B: be able to return goods at any time', 'C: get free products', 'D: set product prices'], answer: 'A', explanation: 'Consumers have the right to accurate and complete information about products.' },
  { id: 'com76', year: 2024, topic: 'Consumer Protection', difficulty: 'medium', question: 'Caveat emptor means', options: ['A: let the seller beware', 'B: let the buyer beware', 'C: goods once sold cannot be returned', 'D: the customer is always right'], answer: 'B', explanation: 'Caveat emptor places the responsibility on the buyer to examine goods before purchase.' },
  { id: 'com77', year: 2024, topic: 'Consumer Protection', difficulty: 'hard', question: 'A consumer who buys defective goods can seek redress through', options: ['A: the manufacturers only', 'B: the Consumer Protection Council or court', 'C: the bank', 'D: the stock exchange'], answer: 'B', explanation: 'Consumers can file complaints with the FCCPC or pursue legal action.' },
  { id: 'com78', year: 2024, topic: 'Consumer Protection', difficulty: 'easy', question: 'The right to safety means consumers are protected against', options: ['A: high prices', 'B: hazardous products', 'C: product shortages', 'D: import restrictions'], answer: 'B', explanation: 'Consumers have the right to be protected from dangerous or unsafe products.' },
  { id: 'com79', year: 2024, topic: 'Capital Market', difficulty: 'medium', question: 'The stock exchange is a market for', options: ['A: short-term securities', 'B: long-term securities', 'C: foreign currencies', 'D: commodities'], answer: 'B', explanation: 'The stock exchange trades long-term securities like shares and bonds.' },
  { id: 'com80', year: 2024, topic: 'Capital Market', difficulty: 'medium', question: 'A share that gives the holder voting rights is a', options: ['A: preference share', 'B: ordinary share', 'C: debenture', 'D: treasury bill'], answer: 'B', explanation: 'Ordinary (equity) shares carry voting rights at general meetings.' },
  { id: 'com81', year: 2024, topic: 'Capital Market', difficulty: 'hard', question: 'The primary market deals with', options: ['A: trading of existing securities', 'B: issuance of new securities', 'C: foreign exchange trading', 'D: commodities trading'], answer: 'B', explanation: 'The primary market is where new securities are first issued to investors.' },
  { id: 'com82', year: 2024, topic: 'Capital Market', difficulty: 'easy', question: 'The Nigerian Stock Exchange (NGX) is located in', options: ['A: Abuja', 'B: Lagos', 'C: Port Harcourt', 'D: Kano'], answer: 'B', explanation: "The NGX is headquartered in Lagos, Nigeria's financial hub." },
  { id: 'com83', year: 2024, topic: 'Capital Market', difficulty: 'medium', question: 'A debenture is a', options: ['A: share certificate', 'B: loan instrument issued by a company', 'C: government bond only', 'D: bank statement'], answer: 'B', explanation: 'A debenture is a debt instrument acknowledging a loan to a company.' },
  { id: 'com84', year: 2024, topic: 'Capital Market', difficulty: 'hard', question: 'The Securities and Exchange Commission (SEC) regulates', options: ['A: the banking industry', 'B: the capital market', 'C: insurance companies', 'D: the telecommunications sector'], answer: 'B', explanation: 'SEC Nigeria regulates the capital market to protect investors.' },
  { id: 'com85', year: 2024, topic: 'Business Finance', difficulty: 'easy', question: 'Funds needed for day-to-day operations of a business are called', options: ['A: fixed capital', 'B: working capital', 'C: equity capital', 'D: loan capital'], answer: 'B', explanation: 'Working capital covers short-term operational expenses.' },
  { id: 'com86', year: 2024, topic: 'Business Finance', difficulty: 'medium', question: 'The cost of borrowing money is called', options: ['A: principal', 'B: interest', 'C: dividend', 'D: premium'], answer: 'B', explanation: 'Interest is the charge for using borrowed funds.' },
  { id: 'com87', year: 2024, topic: 'Business Finance', difficulty: 'medium', question: 'An overdraft is a form of', options: ['A: long-term financing', 'B: short-term borrowing from a bank', 'C: equity financing', 'D: trade credit'], answer: 'B', explanation: 'An overdraft allows a customer to withdraw more than their account balance, a short-term facility.' },
  { id: 'com88', year: 2024, topic: 'Business Finance', difficulty: 'hard', question: 'The portion of profits distributed to shareholders is called', options: ['A: interest', 'B: dividend', 'C: retained earnings', 'D: capital gain'], answer: 'B', explanation: 'Dividends are payments made to shareholders from company profits.' },
  { id: 'com89', year: 2024, topic: 'Business Finance', difficulty: 'easy', question: 'A loan secured against a property is called a', options: ['A: mortgage', 'B: debenture', 'C: bond', 'D: bill of exchange'], answer: 'A', explanation: 'A mortgage is a loan secured by real property.' },
  { id: 'com90', year: 2024, topic: 'Business Finance', difficulty: 'medium', question: 'Trade credit is a form of', options: ['A: external financing', 'B: internal financing', 'C: government grant', 'D: share capital'], answer: 'A', explanation: 'Trade credit is credit extended by suppliers to buyers.' },
  { id: 'com91', year: 2024, topic: 'Trade', difficulty: 'medium', question: 'Visible trade refers to trade in', options: ['A: services', 'B: physical goods', 'C: financial instruments', 'D: intellectual property'], answer: 'B', explanation: 'Visible trade involves tangible goods like machinery and food.' },
  { id: 'com92', year: 2024, topic: 'Advertising', difficulty: 'hard', question: 'The effectiveness of an advertisement can be measured by', options: ['A: production cost', 'B: the response rate and sales increase', 'C: the length of the ad', 'D: the colour used'], answer: 'B', explanation: 'Ad effectiveness is measured by its impact on consumer response and sales.' },
  { id: 'com93', year: 2024, topic: 'Insurance', difficulty: 'medium', question: 'The principle of utmost good faith requires that', options: ['A: the insured pays premiums on time', 'B: both parties disclose all material facts', 'C: the insurer always pays claims', 'D: the insured can change terms anytime'], answer: 'B', explanation: 'Utmost good faith (uberrimae fidei) requires full disclosure of all relevant information.' },
  { id: 'com94', year: 2024, topic: 'Business Units', difficulty: 'medium', question: 'A private limited company is restricted from', options: ['A: having more than 50 shareholders', 'B: inviting the public to subscribe for shares', 'C: distributing dividends', 'D: holding board meetings'], answer: 'B', explanation: 'Private companies cannot offer shares to the general public.' },
  { id: 'com95', year: 2024, topic: 'Commerce & E-commerce', difficulty: 'hard', question: 'The term digital divide refers to the gap between', options: ['A: developed and developing countries in internet access', 'B: online and offline businesses', 'C: large and small companies', 'D: importers and exporters'], answer: 'A', explanation: 'The digital divide describes unequal access to digital technology and the internet.' },
  { id: 'com96', year: 2024, topic: 'Money & Finance', difficulty: 'hard', question: 'The quantity theory of money states that', options: ['A: money supply directly affects price levels', 'B: interest rates determine money demand', 'C: inflation is caused by low savings', 'D: government spending drives growth'], answer: 'A', explanation: 'The quantity theory posits a direct relationship between money supply and prices.' },
  { id: 'com97', year: 2024, topic: 'Transportation', difficulty: 'hard', question: 'The CIF value of goods includes', options: ['A: only the cost of goods', 'B: cost, insurance, and freight', 'C: cost, import duty, and freight', 'D: cost, insurance, and profit'], answer: 'B', explanation: 'CIF stands for Cost, Insurance, and Freight.' },
  { id: 'com98', year: 2024, topic: 'Warehousing', difficulty: 'medium', question: 'Cold storage is used primarily for', options: ['A: dry goods', 'B: perishable food items', 'C: metallic items', 'D: clothing'], answer: 'B', explanation: 'Cold storage preserves perishable items like food at controlled temperatures.' },
  { id: 'com99', year: 2024, topic: 'Marketing', difficulty: 'hard', question: 'The product life cycle stage where sales growth slows and profit stabilises is', options: ['A: introduction', 'B: growth', 'C: maturity', 'D: decline'], answer: 'C', explanation: 'The maturity stage sees peak sales with slowing growth.' },
  { id: 'com100', year: 2024, topic: 'Consumer Protection', difficulty: 'medium', question: 'The right to choose means consumers should have', options: ['A: access to a variety of products at competitive prices', 'B: the ability to set prices', 'C: guaranteed product quality', 'D: free home delivery'], answer: 'A', explanation: 'Consumers should have access to diverse products and fair prices.' },
  { id: 'com101', year: 2024, topic: 'Capital Market', difficulty: 'medium', question: 'A bull on the stock market expects', options: ['A: falling prices', 'B: rising prices', 'C: stable prices', 'D: market closure'], answer: 'B', explanation: 'A bull anticipates rising share prices and buys accordingly.' },
  { id: 'com102', year: 2024, topic: 'Business Finance', difficulty: 'hard', question: 'Retained earnings are an example of', options: ['A: external financing', 'B: internal financing', 'C: debt financing', 'D: government funding'], answer: 'B', explanation: 'Retained earnings are profits kept in the business for reinvestment, an internal source.' },
  { id: 'com103', year: 2024, topic: 'Trade', difficulty: 'hard', question: 'The invisible balance of trade refers to trade in', options: ['A: goods only', 'B: services like banking, insurance, and tourism', 'C: agricultural products', 'D: manufactured goods'], answer: 'B', explanation: 'Invisible trade includes services and intangible items.' },
  { id: 'com104', year: 2024, topic: 'Advertising', difficulty: 'easy', question: 'A medium of advertising that reaches a local audience effectively is', options: ['A: national television', 'B: local radio', 'C: international magazine', 'D: global website'], answer: 'B', explanation: 'Local radio targets specific geographic communities effectively.' },
  { id: 'com105', year: 2024, topic: 'Insurance', difficulty: 'medium', question: 'Underinsurance occurs when', options: ['A: goods are insured for more than their value', 'B: goods are insured for less than their actual value', 'C: no insurance policy exists', 'D: the premium is unpaid'], answer: 'B', explanation: 'Underinsurance means the sum insured is less than the actual value of the property.' },
];

